func Test_DedupBasic(t *testing.T) {
	// Deduplicate repeated lines
	var texts []string
	if err := json.Unmarshal([]byte(`["line1","line1","line2","line2","line3"]`), &texts); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	result, err := kreuzberg.DedupText(texts)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	if result == nil {
		t.Fatalf("expected non-nil result")
	}
	value := *result
	if !strings.Contains(strings.Join(value, " "), `line1`) {
		t.Errorf("expected to contain %s, got %v", `line1`, value)
	}
}

